{
  "title": "बुनियादी मूव सेमैंटिक्स",
  "group": "स्वामित्व",
  "options": [
    {
      "text": "नमस्ते, !",
      "hint": "सोचिए कि 'philosopher' को मूव करने के बाद उसका क्या होता है"
    },
    {
      "text": "नमस्ते, Zeno of Citium!",
      "hint": "एक बार मान मूव हो जाने के बाद, क्या हम इसका उपयोग कर सकते हैं?"
    },
    {
      "text": "नमस्ते, Zeno of Elea!",
      "hint": "स्ट्रिंग में 'Citium' है, 'Elea' नहीं"
    },
    {
      "text": "नमस्ते, Marcus Aurelius",
      "hint": "जांचें कि यह स्ट्रिंग सामग्री से मेल खाता है या नहीं"
    },
    {
      "text": "संकलन त्रुटि: मूव के बाद मान उधार लिया गया"
    },
    {
      "text": "रनटाइम त्रुटि: नल पॉइंटर अपवाद",
      "hint": "Rust इन समस्याओं को संकलन समय पर पकड़ लेता है"
    }
  ],
  "questionProse": [
    "जब आप यह कोड चलाते हैं तो क्या होता है? आउटपुट या त्रुटि का अनुमान लगाने का प्रयास करें:"
  ],
  "explanationProse": [
    "यह कोड Rust के स्वामित्व नियमों के कारण संकलित नहीं होता। जब हम `philosopher` को `greeting` को असाइन करते हैं, तो String का स्वामित्व `greeting` में स्थानांतरित हो जाता है। इस स्थानांतरण के बाद, `philosopher` का उपयोग करना मान्य नहीं रहता।\n\n      इसे ठीक करने के तीन तरीके हैं:\n\n      1. स्ट्रिंग को क्लोन करें (एक नई प्रतिलिपि बनाता है):",
    "2. एक रेफरेंस का उपयोग करें (मान उधार लेता है):",
    "3. एक स्ट्रिंग स्लाइस का उपयोग करें (स्ट्रिंग का भाग उधार लेता है):",
    "प्रत्येक समाधान के अलग-अलग उपयोग के मामले और प्रदर्शन प्रभाव होते हैं। क्लोनिंग अधिक महंगी है लेकिन आपको स्वामित्व देती है, जबकि रेफरेंस सस्ते हैं लेकिन उनमें जीवनकाल की बाधाएं होती हैं।"
  ]
}
